578→    private func applyFitting(for imageSize: NSSize) {
579→        guard imageSize.width > 0, imageSize.height > 0 else { return }
580→        // documentView frame is now set by DualPageContentView.configureSingle/configureDouble
581→        // 計算有效 viewport：scrollView 現在填滿 container，需扣除覆蓋的 statusBar 高度
582→        let viewport = effectiveScrollViewport
583→        guard viewport.width > 0, viewport.height > 0 else {
584→            setMagnificationCentered(1.0)
585→            return
586→        }
587→
588→        if settings.alwaysFitOnOpen {
589→            let fitted = FittingCalculator.calculate(
590→                imageSize: imageSize,
591→                viewportSize: viewport,
592→                options: settings.fittingOptions
593→            )
594→            setMagnificationCentered(fitted.width / imageSize.width)
595→        } else if settings.isManualZoom {
596→            setMagnificationCentered(settings.magnification)
597→        } else {
598→            setMagnificationCentered(scrollView.magnification)
599→        }

930→        lastPrefetchDirection = .none
931→        if settings.dualPageEnabled {
932→            folder.goToLastSpread()
933→        } else {
934→            folder.currentIndex = folder.images.count - 1
935→        }
936→        loadCurrentImage(initialScroll: .top)
937→        updateWindowTitle()
938→    }
939→
940→    /// Space / PageDown：視覺向下捲動一頁，到底部則翻到下一張
941→    /// macOS unflipped: visual bottom = minY ≈ 0, scroll down = decrease Y
942→    private func scrollPageDownOrNext() {
943→        let clipView = scrollView.contentView
944→        let visibleHeight = clipView.bounds.height
945→        let currentMinY = clipView.bounds.minY
946→
947→        // Visual bottom in unflipped coords = minY near 0
948→        if currentMinY <= Constants.scrollEdgeThreshold {
949→            goToNextImage()
950→        } else {
951→            let newY = max(currentMinY - visibleHeight, 0)
952→            clipView.scroll(to: NSPoint(x: clipView.bounds.minX, y: newY))
953→            scrollView.reflectScrolledClipView(clipView)
954→        }
955→    }
956→
957→    /// PageUp：視覺向上捲動一頁，到頂部則翻到上一張
958→    /// macOS unflipped: visual top = maxY ≈ docHeight, scroll up = increase Y
959→    private func scrollPageUpOrPrev() {
960→        let clipView = scrollView.contentView
961→        let visibleHeight = clipView.bounds.height
962→        let currentMinY = clipView.bounds.minY
963→        let docHeight = scrollView.documentView?.frame.height ?? 0
964→
