    guard imageSize.width > 0, imageSize.height > 0 else { return }
    // documentView frame is now set by DualPageContentView.configureSingle/configureDouble
    // 計算有效 viewport：scrollView 現在填滿 container，需扣除覆蓋的 statusBar 高度
