    @objc func toggleArrowUpDownNav(_ sender: Any? = nil) {
        settings.arrowUpDownNavigation.toggle()
        settings.save()
        scrollView.arrowUpDownNavigation = settings.arrowUpDownNavigation
        scrollView.resetEdgeState()
    }

